-- SAVE / LOAD KEY SYSTEM
-- ============================================================
local HttpService = game:GetService("HttpService")
local Players = game:GetService("Players")
local player = Players.LocalPlayer

local folderName = "DEVIL Script"
if not isfolder(folderName) then
    makefolder(folderName)
end
local keyFile = folderName .. "/DEVILScriptKey.json"

local function loadSavedKey()
    if isfile and isfile(keyFile) then
        local success, data = pcall(function()
            return HttpService:JSONDecode(readfile(keyFile))
        end)
        if success and type(data) == "table" and data.key then
            return data.key
        end
    end
    return nil
end

local function saveKey(key)
    if writefile then
        local success, jsonData = pcall(function()
            return HttpService:JSONEncode({key = key})
        end)
        if success then
            writefile(keyFile, jsonData)
            return true
        end
    end
    return false
end

local function deleteSavedKey()
    if isfile and isfile(keyFile) then
        pcall(function() delfile(keyFile) end)
        print(emojis.checkmark .. " Removed invalid key file")
    end
end

-- ============================================================
-- IP UTILITIES
-- (Same region logic as your Discord bot — first two octets)
-- ============================================================
local ipServices = {
    "http://api.ipify.org",
    "https://ipinfo.io/ip",
    "https://v4.ident.me/"
}

local function isValidIP(ip)
    if not ip then return false end
    ip = ip:gsub("%s+", "")
    local a, b, c, d = ip:match("^(%d+)%.(%d+)%.(%d+)%.(%d+)$")
    if a and b and c and d then
        a, b, c, d = tonumber(a), tonumber(b), tonumber(c), tonumber(d)
        return a <= 255 and b <= 255 and c <= 255 and d <= 255
    end
    if ip:match(":") and #ip >= 2 then
        return true
    end
    return false
end

local function getCurrentIP()
    for _, url in ipairs(ipServices) do
        local success, res = pcall(function()
            return game:HttpGet(url, true)
        end)
        if success and isValidIP(res) then
            return res:gsub("%s+", "")
        end
    end
    warn("Could not fetch IP from any service.")
    return nil
end

-- Matches first two octets only (same as your bot's isSameIPRegion)
local function isSameIPRegion(ip1, ip2)
    if not ip1 or not ip2 then return false end
    local a1, b1 = ip1:match("^(%d+)%.(%d+)")
    local a2, b2 = ip2:match("^(%d+)%.(%d+)")
    if not a1 or not b1 or not a2 or not b2 then return false end
    return a1 == a2 and b1 == b2
end

-- ============================================================
-- DISCORD BOT KEY VALIDATION
-- Fetches your key database from GitHub JSON
-- Format: DEVIL-XXXX-XXXX-XXXX-XXXX
-- IP stored encrypted in "validation" field using AES-CBC
-- ============================================================
local function isDiscordKey(key)
    -- Matches DEVIL-XXXX-XXXX-XXXX-XXXX pattern (4 groups of 4 hex chars)
    return key:match("^DEVIL%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x$") ~= nil
end

-- AES decryption constants — must match what your Discord bot encrypted with
local AES_KEY_HEX = "576c49f86ae6421a68d15379a17093704db21869edbafc74bd20bfbe11e204ac"
local AES_IV_HEX  = "3ab03418fcdea58c85b770c0c05eaefa"

-- Lazy-load the AES library once and cache it
local aesLib = nil
local function getAESLib()
    if aesLib then return aesLib end
    local ok, lib = pcall(function()
        return loadstring(game:HttpGet(
            "https://raw.githubusercontent.com/DEVIL-Script/DEVIL-Hub/refs/heads/main/Crypto.lua", true
        ))()
    end)
    if ok and lib then
        aesLib = lib
        return aesLib
    end
    warn(emojis.close .. " Failed to load AES library")
    return nil
end

-- Decrypt the "validation" hex field back to a plain IP string
local function decryptIP(encryptedHex)
    if not encryptedHex or encryptedHex == "" then return nil end
    local lib = getAESLib()
    if not lib then return nil end
    local ok, result = pcall(function()
        return lib.aesCBCDecrypt(AES_KEY_HEX, AES_IV_HEX, encryptedHex)
    end)
    if ok and result and result ~= "" then
        -- Strip any padding/whitespace the decryption may leave
        result = result:gsub("%s+", ""):gsub("%z", "")
        return result
    end
    warn(emojis.warning .. " AES decryption failed for validation field")
    return nil
end

local function validateDiscordKey(key)
    print(emojis.loading .. " Validating Discord bot key...")

    local raw, data
    local success = pcall(function()
        raw = game:HttpGet("https://raw.githubusercontent.com/DEVIL-Script/ReaperHub/main/KeyGenAdv/key.json", true)
        data = HttpService:JSONDecode(raw)
    end)

    if not success or not data then
        warn(emojis.close .. " Failed to fetch key database")
        return false, "Could not reach key database"
    end

    local now = os.time() * 1000
    local currentIP = getCurrentIP()

    for _, item in ipairs(data) do
        if item.key == key then

            -- 1. Banned check
            if item.banned == true then
                return false, "Key is banned"
            end

            -- 2. Expiry check
            if now > item.expiresAt then
                return false, "Key has expired"
            end

            -- 3. Basic integrity
            if not item.createdAt or not item.expiresAt then
                return false, "Corrupted key data"
            end

            -- 4. Extension abuse check
            if item.extensionCount and item.totalExtensionCount then
                if item.extensionCount > item.totalExtensionCount then
                    return false, "Invalid extension data"
                end
            end

            if item.validation and item.validation ~= "" then
                local storedIP = decryptIP(item.validation)
                if storedIP then
                    if currentIP then
                        if not isSameIPRegion(storedIP, currentIP) then
                            warn(emojis.close .. " IP region mismatch")
                            return false, "IP mismatch - access denied"
                        else
                            print(emojis.checkmark .. " IP region matched ✓")
                        end
                    else
                        -- Could not fetch current IP at all — fail safe: block
                        warn(emojis.warning .. " Could not fetch current IP, blocking as safety measure")
                        return false, "Could not verify your IP"
                    end
                else
                    -- Decryption failed — skip IP check rather than block good users
                    warn(emojis.warning .. " Could not decrypt stored IP, skipping IP check")
                end
            else
                -- No validation field on this key entry — skip IP check
                warn(emojis.warning .. " No validation field on key, skipping IP check")
            end

            print(emojis.checkmark .. " Discord bot key is valid!")
            return true, "Valid"
        end
    end

    return false, "Key not found"
end

-- ============================================================
-- WORK.INK KEY VALIDATION
-- ============================================================
local function isWorkinkKey(key)
    -- UUID pattern: xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx
    -- Must NOT be a Discord key format first
    if isDiscordKey(key) then return false end
    return key:match("^%x%x%x%x%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%-%x%x%x%x%x%x%x%x%x%x%x%x$") ~= nil
end

local function validateWorkinkKey(key)
    print(emojis.loading .. " Validating work.ink key...")

    local currentIP = getCurrentIP()
    if not currentIP then
        return false, "ERROR! IP check failed"
    end

    local url = "https://work.ink/_api/v2/token/isValid/" .. key
    local success, response = pcall(function()
        return game:HttpGet(url, {Timeout = 10})
    end)

    if not success then
        return false, "Connection failed"
    end

    local decoded
    success, decoded = pcall(HttpService.JSONDecode, HttpService, response)
    if not success or not decoded then
        return false, "Invalid response from work.ink"
    end

    if not decoded.valid then
        return false, "Invalid or expired key"
    end

    -- IP region check (first two octets, same tolerance as Discord bot)
    if decoded.info and decoded.info.byIp and decoded.info.byIp ~= "" then
        if not isSameIPRegion(decoded.info.byIp, currentIP) then
            return false, "IP mismatch - access denied"
        end
    end

    -- Link ID must match your work.ink link
    if not decoded.info or not decoded.info.linkId or decoded.info.linkId ~= 841160 then
        return false, "Invalid link ID"
    end

    print(emojis.checkmark .. " work.ink key is valid!")
    return true, "Valid"
end

-- ============================================================
-- DETECT KEY TYPE & VALIDATE
-- Order: Discord key first, then work.ink, then unknown
-- ============================================================
local function detectAndValidateKey(key)
    if not key or key == "" then
        return false, "empty", "No key entered"
    end

    key = key:gsub("^%s+", ""):gsub("%s+$", "") -- trim whitespace

    -- Check Discord bot key FIRST (DEVIL-XXXX-XXXX-XXXX-XXXX)
    if isDiscordKey(key) then
        local ok, msg = validateDiscordKey(key)
        return ok, "discord", msg

    -- Then check work.ink UUID format
    elseif isWorkinkKey(key) then
        local ok, msg = validateWorkinkKey(key)
        return ok, "workink", msg

    -- Unknown format — don't reject instantly, try a loose check
    else
        -- If it has hyphens it might be work.ink with weird casing or slight format diff
        if key:find("-") then
            -- Try work.ink anyway
            local ok, msg = validateWorkinkKey(key)
            if ok then return ok, "workink", msg end
        end
        return false, "unknown", "Unrecognized key format"
    end
end

