-- ============================================================
-- VALIDATE SAVED KEY ON STARTUP
-- ============================================================
local function validateKey(key)
    print(emojis.loading .. " Validating saved key:", string.sub(key, 1, 10) .. "...")
    local ok, keyType, msg = detectAndValidateKey(key)

    if ok then
        print(emojis.checkmark .. " Saved key is valid, loading script...")
        loadMainScript(keyType)
        return true
    else
        warn(emojis.close .. " Saved key invalid: " .. msg)
        deleteSavedKey()
        return false
    end
end

local savedKey = loadSavedKey()
print(emojis.checkmark .. " Saved Key: ", savedKey)
if savedKey then
    local isValid = validateKey(savedKey)
    if isValid then
        print(emojis.checkmark .. " Valid key found, loading script...")
    else
        print(emojis.close .. " Invalid saved key, showing key UI...")
    end
else
    print(emojis.close .. " No saved key found")
end

